+  exit 0
+fi
+
+if [ "${1:-}" = "switch" ] && [ "${2:-}" = "claude" ] && [ "${3:-}" = "--next" ] && [ "${4:-}" = "--json" ]; then
+  prev="$(cat "$STATE_FILE" 2>/dev/null || true)"
+  if [ "$prev" = "claude-b" ]; then
